import {useEffect} from 'react';
import {useForm, FormProvider} from 'react-hook-form';
import Title from '../../sharedV2/Title';
import TextField from '/app/components/sharedV2/TextField';
import Checkbox from '../../sharedV2/CheckBox';
import DayPickerInput from '/app/components/sharedV2/DayPickerInput';
import RenderSubmitButtons from '../formV2/RenderButtons';
import historizationStore from '/app/stores/modules/historizationStore';
import dayjs from 'dayjs';
import * as Yup from 'yup';
import {yupResolver} from '@hookform/resolvers/yup';
import BtnReturn from '../BtnReturn';

const {i18n} = __;
const {dateUiFormat, dateApiFormat} = __.app;

const validationSchema = Yup.object().shape({
  value: Yup.number()
    .typeError(i18n.t('Yup.validation.required'))
    .positive(i18n.t('form.errors.positiveNumber'))
    .required(i18n.t('Yup.validation.required')),
});

const HistorizationForm = ({
  value,
  dateBegin,
  dateEnd,
  resource,
  resourceId,
  type,
  code,
  onCloseModal,
  returnOnSubmit,
  title,
  name,
}) => {
  const methods = useForm({
    resolver: yupResolver(validationSchema),
    defaultValues: {
      value: value || '',
      dateBegin: dateBegin ? dayjs(dateBegin, dateApiFormat).format(dateUiFormat) : dayjs().format(dateUiFormat),
      dateEnd: dateEnd ? dateEnd : dayjs().format(dateUiFormat),
      isFromOrigin: dateBegin === null || dateBegin === 'null',
      isToNow: dateEnd === null || dateEnd === 'null',
    },
  });

  const {
    handleSubmit,
    watch,
    setValue,
    formState: {errors},
  } = methods;

  const isFromOrigin = watch('isFromOrigin');
  const isToNow = watch('isToNow');

  // Ensure date fields are set when checkboxes are unchecked
  useEffect(() => {
    if (!isFromOrigin) {
      setValue('dateBegin', dayjs().format(dateUiFormat));
    }
  }, [isFromOrigin, setValue]);

  useEffect(() => {
    if (!isToNow) {
      setValue('dateEnd', dayjs().format(dateUiFormat));
    }
  }, [isToNow, setValue]);

  const submit = (data) => {
    const payload = {
      ...data,
      dateBegin: data.isFromOrigin ? null : data.dateBegin,
      dateEnd: data.isToNow ? null : data.dateEnd,
      resource,
      resourceId,
      type,
      code,
    };

    historizationStore
      .addHistorizedData(payload)
      .then(() => {
        __.ui.notify({level: 'success', message: i18n.t('HistorizationForm.added')});
        if (returnOnSubmit) {
          __.router.location.historyBack();
        }
      })
      .catch(() => {
        __.ui.notify({level: 'error', message: i18n.t('HistorizationForm.error')});
      });

    if (onCloseModal) {
      onCloseModal();
    }
  };

  return (
    <>
      <BtnReturn />
      <div className='twpf'>
        <div className='tw-p-9 tw-mt-2 tw-flex tw-flex-col tw-gap-4'>
          <Title title={title} />
          <FormProvider {...methods}>
            <form onSubmit={handleSubmit(submit)}>
              <TextField
                name='value'
                label={name}
                type='number'
                errors={errors.value?.message}
              />

              <div className='tw-flex tw-justify-between'>
                <div>
                  {!isFromOrigin && (
                    <DayPickerInput
                      name='dateBegin'
                      label={i18n.t('HistorizationForm.startDate')}
                      onChange={(value) => setValue('dateBegin', value)}
                    />
                  )}
                  <Checkbox
                    label={i18n.t('HistorizationForm.fromOrigin')}
                    name='isFromOrigin'
                  />
                </div>
                <div>
                  {!isToNow && (
                    <DayPickerInput
                      name='dateEnd'
                      label={i18n.t('HistorizationForm.endDate')}
                      onChange={(value) => setValue('dateEnd', value)}
                    />
                  )}
                  <Checkbox
                    label={i18n.t('HistorizationForm.toNow')}
                    name='isToNow'
                  />
                </div>
              </div>
              <RenderSubmitButtons />
            </form>
          </FormProvider>
        </div>
      </div>
    </>
  );
};

export default HistorizationForm;
